// WebhookEvent
//
// A webhook event.
//
// An event represent something that happened in the system
// that should be sent to the webhook endpoint.
//
// It can be delivered multiple times until it's marked as succeeded,
// each one creating a new delivery.
type WebhookEvent struct {
	// CreatedAt: Creation timestamp of the object.
	CreatedAt string `json:"created_at"`
	// ModifiedAt: Last modification timestamp of the object.
	ModifiedAt *string `json:"modified_at"`
	// ID: The ID of the object.
	ID string `json:"id"`
	// LastHTTPCode: Last HTTP code returned by the URL. `null` if no delviery has been attempted or if the endpoint was unreachable.
	LastHTTPCode *int `json:"last_http_code,omitempty"`
	// Succeeded: Whether this event was successfully delivered. `null` if no delivery has been attempted.
	Succeeded *bool `json:"succeeded,omitempty"`
	// Skipped: Whether this event was skipped because the webhook endpoint was disabled.
	Skipped bool `json:"skipped"`
	// Payload: The payload of the webhook event.
	Payload *string          `json:"payload"`
	Type    WebhookEventType `json:"type"`
	// IsArchived: Whether this event is archived. Archived events can't be redelivered, and the payload is not accessible anymore.
	IsArchived bool `json:"is_archived"`
}
